                raise TypeError(f"{name} must be an int or None")
            if value is not None and value < 0:
                raise ValueError(f"{name} must be greater than or equal to zero")
        self.max_cookies = max_cookies
        self.max_cookies_per_domain = max_cookies_per_domain
        self._cookies: dict[tuple[str, str, str], dict[str, typing.Any]] = {}
        self._creation = 0
        if cookies is not None:
            self.update(cookies)

    @staticmethod
    def _domain_matches(host: str, domain: str) -> bool:
        host, domain = host.lower(), domain.lower()
        return host == domain or host.endswith("." + domain)

    @staticmethod
    def _path_matches(request_path: str, cookie_path: str) -> bool:
        return request_path == cookie_path or (
            request_path.startswith(cookie_path)
            and (cookie_path.endswith("/") or request_path[len(cookie_path)] == "/")
        )

    @staticmethod
    def _default_path(request_path: str) -> str:
        if not request_path.startswith("/") or request_path.count("/") <= 1:
            return "/"
        return request_path.rsplit("/", 1)[0] or "/"

