def test_cookie_store_extracts_and_sends_matching_cookies():
    store = httpx.CookieStore()
    request = httpx.Request("GET", "https://example.com/sub/page")
    response = httpx.Response(
        200,
        request=request,
        headers={
            "set-cookie": (
                "host=one; Path=/sub, domain=two; Domain=example.com; Path=/; "
                "Secure"
            )
        },
    )
    store.extract_cookies(response)

    outgoing = httpx.Request("GET", "https://sub.example.com/sub/x")
    store.set_cookie_header(outgoing)
    assert outgoing.headers["cookie"] == "domain=two"

    outgoing = httpx.Request("GET", "https://example.com/submarine")
    store.set_cookie_header(outgoing)
    assert outgoing.headers["cookie"] == "domain=two"


def test_cookie_store_default_path_host_only_and_secure():
    store = httpx.CookieStore()
    request = httpx.Request("GET", "https://example.com/one/two")
    response = httpx.Response(
        200, request=request, headers={"set-cookie": "a=; Secure"}
    )
    store.extract_cookies(response)

    assert "cookie" not in httpx.Request("GET", "https://sub.example.com/one/x").headers
    outgoing = httpx.Request("GET", "https://example.com/one/x", cookies=store)
    assert outgoing.headers["cookie"] == "a="
    assert (
        "cookie"
        not in httpx.Request("GET", "http://example.com/one/x", cookies=store).headers
    )


